// ── Saalai Kural ingestion mapper: data.gov.in record -> /api/roads/ingest ──
// Adjust COLS to your dataset's REAL column names (left = our schema, right = candidates).
const COLS = {
  name:               ['road_name','name','nh_no','nh_number','road','section','stretch','project_name'],
  contractor_name:    ['contractor','contractor_name','agency','executing_agency','concessionaire'],
  contractor_contact: ['contractor_contact','contact','phone','mobile'],
  jurisdiction_dept:  ['department','dept','authority','implementing_agency','division'],
  budget_sanctioned:  ['sanctioned_cost','project_cost','cost','sanctioned_amount','total_cost','tpc'],
  budget_spent:       ['expenditure','amount_spent','cumulative_expenditure','expenditure_incurred'],
  last_relayed_date:  ['completion_date','last_updated','as_on_date','date','updated_on'],
};
// If the dataset reports money in CRORES, set this to 10000000 to store rupees.
const BUDGET_MULTIPLIER = 1;

const root = $input.first().json || {};
const records = root.records || root.data || root.rows || [];

function pick(row, keys) {
  for (const k of keys) {
    const v = row[k];
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return undefined;
}
function num(v) {
  if (v === undefined) return 0;
  const n = parseFloat(String(v).replace(/[^0-9.]/g, ''));
  return isNaN(n) ? 0 : n;
}
function inferType(name) {
  const s = ' ' + String(name).toUpperCase() + ' ';
  if (s.includes('NATIONAL HIGHWAY') || s.includes('NH')) return 'NH';
  if (s.includes('STATE HIGHWAY') || s.includes(' SH')) return 'SH';
  if (s.includes('MDR') || s.includes('MAJOR DISTRICT')) return 'MDR';
  return 'MDR';
}

const seen = new Set();
const roads = [];
for (const row of records) {
  const rawName = pick(row, COLS.name);
  if (!rawName) continue;                 // never invent a road without a real name
  const name = String(rawName).trim();
  const key = name.toLowerCase();
  if (seen.has(key)) continue;            // de-dupe within a batch
  seen.add(key);
  const type = inferType(name);
  const deptDefault = type === 'NH'
    ? 'National Highways Authority'
    : type === 'SH' ? 'State Highways' : 'Rural Development & Panchayat Raj';
  roads.push({
    name,
    type,
    jurisdiction_dept: pick(row, COLS.jurisdiction_dept) || deptDefault,
    contractor_name: pick(row, COLS.contractor_name) || null,
    contractor_contact: pick(row, COLS.contractor_contact) || null,
    budget_sanctioned: num(pick(row, COLS.budget_sanctioned)) * BUDGET_MULTIPLIER,
    budget_spent: num(pick(row, COLS.budget_spent)) * BUDGET_MULTIPLIER,
    last_relayed_date: pick(row, COLS.last_relayed_date) || null,
    maintenance_history: [],
  });
}

console.log('Saalai Kural ingestion: mapped ' + roads.length + ' road(s) from ' + records.length + ' record(s).');
return [{ json: { roads, count: roads.length } }];
